import { DashboardLayout } from "@/components/dashboard/DashboardLayout";
import { StatsCard } from "@/components/dashboard/StatsCard";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { DollarSign, ShoppingCart, TrendingUp, Users, Package, Store, Activity, Star, Clock } from "lucide-react";
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  PieChart,
  Pie,
  Cell,
  LineChart,
  Line,
  Legend
} from "recharts";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Skeleton } from "@/components/ui/skeleton";

interface DashboardStats {
  total_users: number;
  total_admins: number;
  total_vendors: number;
  total_buyers: number;
  vendors_pending: number;
  vendors_approved: number;
  vendors_suspended: number;
  total_products: number;
  active_products: number;
  draft_products: number;
  total_orders: number;
  total_revenue: number;
  pending_orders: number;
  new_users_week: number;
  new_orders_week: number;
}

const COLORS = ["#8B5CF6", "#06B6D4", "#F59E0B", "#10B981", "#EF4444"];

const AdminAnalytics = () => {
  // 1. Fetch main dashboard stats (updated in real-time via refetchInterval)
  const { data: stats, isLoading: statsLoading } = useQuery({
    queryKey: ["admin-dashboard-stats-realtime"],
    queryFn: async () => {
      const { data, error } = await (supabase
        .from("admin_dashboard_stats" as any)
        .select("*")
        .single() as any);
      if (error) throw error;
      return data as DashboardStats;
    },
    // Real-time polling every 5 seconds
    refetchInterval: 5000,
  });

  // 2. Fetch recent orders for status distribution
  const { data: orders = [], isLoading: ordersLoading } = useQuery({
    queryKey: ["admin-all-orders-realtime"],
    queryFn: async () => {
      const { data, error } = await (supabase
        .from("orders" as any)
        .select("status, total_amount, created_at") as any);
      if (error) throw error;
      return data;
    },
    refetchInterval: 5000,
  });

  // 3. Fetch top vendors
  const { data: topVendors = [], isLoading: vendorsLoading } = useQuery({
    queryKey: ["admin-top-vendors-realtime"],
    queryFn: async () => {
      const { data, error } = await (supabase
        .from("vendor_management_view" as any)
        .select("*")
        .eq("vendor_status", "approved")
        .order("total_sales", { ascending: false })
        .limit(5) as any);
      if (error) throw error;
      return data;
    },
    refetchInterval: 5000,
  });

  // Compute Order Status Distribution
  const orderStatusCounts = orders.reduce((acc: any, order: any) => {
    acc[order.status] = (acc[order.status] || 0) + 1;
    return acc;
  }, {});

  const orderStatusData = Object.keys(orderStatusCounts).map(status => ({
    name: status,
    value: orderStatusCounts[status]
  }));

  // Top Vendors Formatting for BarChart
  const topVendorsData = topVendors.map((v: any) => ({
    name: v.store_name || v.full_name || "Unknown",
    sales: v.total_sales || 0,
  }));

  // Average Order Value
  const avgOrderValue = stats?.total_orders && stats.total_orders > 0 
    ? stats.total_revenue / stats.total_orders 
    : 0;

  // Mock Trend Data for Charts (since we don't have a time-series view built yet)
  // In a real application, you'd fetch this using a custom Postgres function grouped by day/month
  const revenueTrendData = [
    { name: "Mon", revenue: 1200 },
    { name: "Tue", revenue: 1900 },
    { name: "Wed", revenue: 1500 },
    { name: "Thu", revenue: 2200 },
    { name: "Fri", revenue: 3100 },
    { name: "Sat", revenue: Math.max(3000, (stats?.total_revenue || 0) * 0.1) },
    { name: "Sun", revenue: Math.max(4000, (stats?.total_revenue || 0) * 0.15) },
  ];

  if (statsLoading || ordersLoading || vendorsLoading) {
    return (
      <DashboardLayout type="admin" title="Analytics (Live)">
        <div className="space-y-6">
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
             {[1,2,3,4].map(n => <Skeleton key={n} className="h-28 w-full rounded-xl" />)}
          </div>
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
             <Skeleton className="h-[400px] w-full rounded-xl" />
             <Skeleton className="h-[400px] w-full rounded-xl" />
          </div>
        </div>
      </DashboardLayout>
    );
  }

  return (
    <DashboardLayout type="admin" title="Live Analytics Overview">
      <div className="mb-4 flex items-center justify-between">
        <p className="text-muted-foreground">Monitoring your platform metrics in real-time.</p>
        <div className="flex items-center gap-2 px-3 py-1 bg-emerald-500/10 text-emerald-600 rounded-full text-sm font-medium">
          <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse" />
          Live connection active
        </div>
      </div>

      {/* Stats Overview */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 mb-6">
        <StatsCard
          title="Total Revenue"
          value={`GHΓé╡${(stats?.total_revenue || 0).toLocaleString()}`}
          icon={DollarSign}
          variant="primary"
        />
        <StatsCard
          title="Total Orders"
          value={(stats?.total_orders || 0).toLocaleString()}
          icon={ShoppingCart}
          variant="secondary"
        />
        <StatsCard
          title="Active Vendors"
          value={stats?.vendors_approved || 0}
          icon={Store}
        />
        <StatsCard
          title="Avg. Order Value"
          value={`GHΓé╡${avgOrderValue.toFixed(2)}`}
          icon={TrendingUp}
          variant="warning"
        />
      </div>

      {/* Charts Row 1 */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-6">
        {/* Revenue Trend (Line Chart) */}
        <Card className="shadow-sm">
          <CardHeader>
            <CardTitle className="text-lg font-semibold flex items-center gap-2">
              <Activity className="w-5 h-5 text-primary" /> Weekly Revenue Trend
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="h-[300px]">
              <ResponsiveContainer width="100%" height="100%">
                <LineChart data={revenueTrendData}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="hsl(var(--border))" />
                  <XAxis dataKey="name" stroke="hsl(var(--muted-foreground))" fontSize={12} tickLine={false} axisLine={false} />
                  <YAxis 
                    stroke="hsl(var(--muted-foreground))" 
                    fontSize={12} 
                    tickLine={false} 
                    axisLine={false}
                    tickFormatter={(value) => `GHΓé╡${value}`}
                  />
                  <Tooltip
                    contentStyle={{
                      backgroundColor: "hsl(var(--card))",
                      border: "1px solid hsl(var(--border))",
                      borderRadius: "8px",
                    }}
                  />
                  <Line type="monotone" dataKey="revenue" stroke="hsl(var(--primary))" strokeWidth={3} dot={{ r: 4, strokeWidth: 2 }} activeDot={{ r: 6 }} />
                </LineChart>
              </ResponsiveContainer>
            </div>
          </CardContent>
        </Card>

        {/* Top Vendors (Horizontal Bar Chart) */}
        <Card className="shadow-sm">
          <CardHeader>
            <CardTitle className="text-lg font-semibold flex items-center gap-2">
              <Star className="w-5 h-5 text-amber-500" /> Top Vendors by Sales
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="h-[300px]">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={topVendorsData} layout="vertical" margin={{ left: 10, right: 20 }}>
                  <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke="hsl(var(--border))" />
                  <XAxis type="number" stroke="hsl(var(--muted-foreground))" fontSize={12} tickLine={false} axisLine={false} />
                  <YAxis 
                    dataKey="name" 
                    type="category" 
                    stroke="hsl(var(--muted-foreground))" 
                    fontSize={12} 
                    width={90}
                    tickLine={false} 
                    axisLine={false}
                  />
                  <Tooltip
                    cursor={{ fill: 'hsl(var(--muted)/0.4)' }}
                    contentStyle={{
                      backgroundColor: "hsl(var(--card))",
                      border: "1px solid hsl(var(--border))",
                      borderRadius: "8px",
                    }}
                  />
                  <Bar dataKey="sales" fill="#06B6D4" radius={[0, 4, 4, 0]} maxBarSize={40}>
                    {topVendorsData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                    ))}
                  </Bar>
                </BarChart>
              </ResponsiveContainer>
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Charts Row 2 */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-6">

        {/* Order Status Pie Chart */}
        <Card className="shadow-sm">
          <CardHeader>
            <CardTitle className="text-lg font-semibold">Live Order Status Distribution</CardTitle>
          </CardHeader>
          <CardContent>
             <div className="h-[300px] flex items-center justify-center">
               {orderStatusData.length === 0 ? (
                 <p className="text-muted-foreground">No orders available.</p>
               ) : (
                 <ResponsiveContainer width="100%" height="100%">
                    <PieChart>
                      <Pie
                        data={orderStatusData}
                        cx="50%"
                        cy="50%"
                        labelLine={false}
                        outerRadius={100}
                        innerRadius={60}
                        fill="#8884d8"
                        dataKey="value"
                        label={({ name, percent }) => `${name} ${(percent * 100).toFixed(0)}%`}
                      >
                        {orderStatusData.map((entry, index) => (
                          <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                        ))}
                      </Pie>
                      <Tooltip 
                        contentStyle={{ borderRadius: '8px', border: '1px solid hsl(var(--border))' }}
                      />
                      <Legend verticalAlign="bottom" height={36}/>
                    </PieChart>
                 </ResponsiveContainer>
               )}
             </div>
          </CardContent>
        </Card>

        {/* Quick Additional Platform Stats */}
        <div className="space-y-4">
          <Card className="shadow-sm">
            <CardContent className="p-5 flex items-center gap-4">
              <div className="p-3 rounded-xl bg-purple-500/10">
                <Package className="w-6 h-6 text-purple-500" />
              </div>
              <div className="flex-1">
                <p className="text-sm font-medium text-muted-foreground">Platform Products</p>
                <div className="flex items-end gap-2">
                  <h4 className="text-2xl font-bold">{stats?.total_products || 0}</h4>
                  <span className="text-sm text-emerald-500 mb-1">{stats?.active_products || 0} active</span>
                </div>
              </div>
            </CardContent>
          </Card>

          <Card className="shadow-sm">
            <CardContent className="p-5 flex items-center gap-4">
              <div className="p-3 rounded-xl bg-primary/10">
                <Users className="w-6 h-6 text-primary" />
              </div>
              <div className="flex-1">
                <p className="text-sm font-medium text-muted-foreground">Registered Shoppers</p>
                <div className="flex items-end gap-2">
                  <h4 className="text-2xl font-bold">{stats?.total_buyers || 0}</h4>
                  {stats?.new_users_week && (
                    <span className="text-sm text-emerald-500 mb-1">+{stats.new_users_week} this week</span>
                  )}
                </div>
              </div>
            </CardContent>
          </Card>

          <Card className="shadow-sm bg-primary border-primary text-primary-foreground">
            <CardContent className="p-5 flex items-center justify-between">
              <div>
                 <p className="text-primary-foreground/80 font-medium">Pending Approvals</p>
                 <h4 className="text-3xl font-bold mt-1">{stats?.vendors_pending || 0} vendors</h4>
              </div>
              <div className="p-4 bg-primary-foreground/20 rounded-full">
                <Clock className="w-8 h-8 text-white" />
              </div>
            </CardContent>
          </Card>
        </div>

      </div>
    </DashboardLayout>
  );
};

export default AdminAnalytics;
